from flask import Flask, request, jsonify, abort

app = Flask(__name__)

# Simple routes

@app.route('/')
def index():
    return 'Hello, Flask!'

@app.route('/greet/<name>')
def greet(name: str):
    # Return a JSON greeting for the given name
    return jsonify({'message': f'Hello, {name}!'})

# Query-parameter handling

@app.route('/search')
def search():
    q = request.args.get('q', '')
    limit = request.args.get('limit', 10, type=int)
    if not q:
        abort(400, description='Missing required query param: q')
    results = [{'id': i, 'title': f"Result {i} for '{q}'"} for i in range(1, limit + 1)]
    return jsonify({'query': q, 'count': len(results), 'results': results})

# POST endpoint with JSON body

@app.route('/items', methods=['POST'])
def create_item():
    data = request.get_json(silent=True)
    if not data or 'name' not in data:
        abort(400, description="Request body must be JSON with a 'name' field")
    item = {'id': 42, 'name': data['name'], 'created': True}
    return jsonify(item), 201

# Error handlers

@app.errorhandler(404)
def not_found(err):
    return jsonify({'error': str(err)}), 404

@app.errorhandler(400)
def bad_request(err):
    return jsonify({'error': str(err)}), 400

if __name__ == '__main__':
    app.run(debug=True)

