from flask import Flask
from .auth.routes import auth_bp
from .items.routes import items_bp

def create_app():
    app = Flask(__name__)
    app.register_blueprint(auth_bp)   # routes: /auth/login, /auth/logout
    app.register_blueprint(items_bp)  # routes: /items/, /items/<id>
    return app
